import React from "react";

function formatTimestamp(dateString) {
  const date = new Date(dateString);
  return date.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
}

const fakeMessages = [
  { username: "me", text: "Hello!", createdAt: new Date().toISOString() },
  { username: "other", text: "Hey, how are you?", createdAt: new Date().toISOString() },
  { username: "me", text: "Doing great thanks 👍", createdAt: new Date().toISOString() },
];

function App() {
  const username = "me";

  return (
    <div style={styles.container}>
      <h2>Test Chat UI</h2>
      <div style={styles.messages}>
        {fakeMessages.map((msg, i) => {
          const isMine = msg.username === username;
          return (
            <div
              key={i}
              style={{
                ...styles.message,
                ...(isMine ? styles.myMessage : styles.otherMessage),
              }}
            >
              <div style={styles.messageContent}>
                {!isMine && <strong>{msg.username}: </strong>} {msg.text}
                <div
                  style={{
                    ...styles.timestamp,
                    color: isMine ? "rgba(255,255,255,0.8)" : "#666",
                  }}
                >
                  {formatTimestamp(msg.createdAt)}
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

export default App;

// --- Styles ---
const styles = {
  container: {
    maxWidth: "600px",
    margin: "20px auto",
    padding: "10px",
    border: "1px solid #ccc",
    borderRadius: "8px",
    backgroundColor: "#f9f9f9",
  },
  messages: {
    height: "300px",
    overflowY: "auto",
    padding: "10px",
    border: "1px solid #ddd",
    borderRadius: "6px",
    background: "#fff",
    marginBottom: "10px",
    display: "flex",
    flexDirection: "column",
  },
  message: {
    marginBottom: "8px",
    display: "flex",
    flexDirection: "column",
  },
  myMessage: {
    alignSelf: "flex-end",
    background: "#007bff",
    color: "#fff",
    borderRadius: "16px 16px 0 16px",
  },
  otherMessage: {
    alignSelf: "flex-start",
    background: "#f1f1f1",
    color: "#000",
    borderRadius: "16px 16px 16px 0",
  },
  messageContent: {
    maxWidth: "70%",
    minWidth: "120px",
    padding: "8px 12px",
    paddingBottom: "20px", // extra space for timestamp
    position: "relative",
    wordBreak: "break-word",
    display: "flex",
    flexDirection: "column",
  },
  timestamp: {
    fontSize: "0.65em",
    position: "absolute",
    bottom: "4px",
    right: "10px", // always bottom-right
    opacity: 0.7,
  },
};
